using System;
using System.Collections;
using System.Collections.Generic;
using UnityEngine;

public class PlayerController : MonoBehaviour
{

    [SerializeField] private float Speed = 5.0f;
    [SerializeField] private Rigidbody2D rb;
    [SerializeField] private float JumpForce = 5.0f;
    [SerializeField] private Transform StartPosition;
    private Vector3 ForceDirection;
    [SerializeField] private float ForceMultiplier = 100f;

    // Start is called before the first frame update
    void Start()
    {

    }

    // Update is called once per frame
    void Update()
    {
        float horizontal = Input.GetAxis("Horizontal");
        float vertical = Input.GetAxis("Vertical");
        float jump = Input.GetAxis("Jump") * JumpForce;

        Vector3 movement = new Vector3(horizontal, 0, vertical);
        rb.AddForce(movement * Speed);

        if (Input.GetKey(KeyCode.Space))
        {
            rb.AddForce(Vector3.up * JumpForce);
        }

    }


    private void OnMouseDown()
    {
        Debug.Log("I pressed the player");

    }

    private void OnMouseUp()
    {
        Vector3 endPosition = ConvertMouseInput();
        ForceDirection = StartPosition.position - endPosition;
        float forceMagnitude = ForceDirection.magnitude;
        rb.bodyType = RigidbodyType2D.Dynamic;
        rb.AddForce(ForceDirection * forceMagnitude * ForceMultiplier);
        rb.gravityScale = 1;

        StartCoroutine(ResetPlayer());

        Debug.Log("Mouse is up" + StartPosition.position + endPosition);
    }

    private void OnMouseDrag()
    {

        transform.position = ConvertMouseInput();

        Debug.Log("Draging the player to = " + ConvertMouseInput());
    }

    IEnumerator ResetPlayer()
    {
        yield return new WaitForSeconds(5f);
        this.transform.position = StartPosition.position;
        rb.gravityScale = 0.0f;
        rb.bodyType = RigidbodyType2D.Static;
    }



    private Vector3 ConvertMouseInput()
    {
        Vector3 mousePosition = Input.mousePosition;

        Vector3 mouseWorldPosition = Camera.main.ScreenToWorldPoint(mousePosition);
        mouseWorldPosition.z = 0;

        return mouseWorldPosition;
    }

}

using System.Collections;
using UnityEngine;

public class PlayerController : MonoBehaviour
{
    [SerializeField] private Rigidbody2D rb;
    [SerializeField] private Transform StartPosition;
    [SerializeField] private float ForceMultiplier = 100f;
    [SerializeField] private float maxDragDistance = 3f;
    [SerializeField] private Birds currentBird;

    private Vector3 forceDirection;
    private bool isDragging;

    private void Awake()
    {
        if (currentBird == null)
        {
            currentBird = GetComponent<Birds>();
        }
    }

    private void OnMouseDown()
    {
        if (rb.bodyType != RigidbodyType2D.Static)
        {
            return;
        }

        isDragging = true;
    }

    private void OnMouseUp()
    {
        if (!isDragging)
        {
            return;
        }

        isDragging = false;
        Vector3 endPosition = GetClampedMouseWorldPosition();
        forceDirection = StartPosition.position - endPosition;
        float forceMagnitude = forceDirection.magnitude;

        rb.bodyType = RigidbodyType2D.Dynamic;
        rb.gravityScale = 1f;
        rb.velocity = Vector2.zero;
        rb.angularVelocity = 0f;
        rb.AddForce(forceDirection * forceMagnitude * ForceMultiplier);

        if (currentBird != null)
        {
            currentBird.OnLaunched();
        }

        StartCoroutine(ResetPlayer());
    }

    private void OnMouseDrag()
    {
        if (!isDragging)
        {
            return;
        }

        transform.position = GetClampedMouseWorldPosition();
    }

    private IEnumerator ResetPlayer()
    {
        yield return new WaitForSeconds(5f);

        transform.position = StartPosition.position;
        rb.velocity = Vector2.zero;
        rb.angularVelocity = 0f;
        rb.gravityScale = 0f;
        rb.bodyType = RigidbodyType2D.Static;

        if (currentBird != null)
        {
            currentBird.ResetBird();
        }
    }

    private Vector3 GetClampedMouseWorldPosition()
    {
        Vector3 mouseWorldPosition = ConvertMouseInput();
        Vector3 offset = mouseWorldPosition - StartPosition.position;

        if (offset.magnitude > maxDragDistance)
        {
            offset = offset.normalized * maxDragDistance;
        }

        Vector3 clampedPosition = StartPosition.position + offset;
        clampedPosition.z = 0f;
        return clampedPosition;
    }

    private Vector3 ConvertMouseInput()
    {
        Vector3 mousePosition = Input.mousePosition;
        Vector3 mouseWorldPosition = Camera.main.ScreenToWorldPoint(mousePosition);
        mouseWorldPosition.z = 0;

        return mouseWorldPosition;
    }
}
